const data = $input.item.json.body || $input.item.json;

const plano = data.plano ? data.plano.toLowerCase() : null;

if (!plano) {
  return { status: "Sob Avaliação Técnica", erro: "Faltam dados críticos (plano)." };
}

let horasMensais = 0;
let deslocamentosInclusos = 0;
let precoRecomendado = 0;
let faixaComercial = "";
let slaAtendimento = "";

switch (plano) {
  case "basic":
    horasMensais = 10;
    deslocamentosInclusos = 2;
    precoRecomendado = 1500;
    faixaComercial = "R$ 1.200 - R$ 1.800";
    slaAtendimento = "48h";
    break;
  case "master":
    horasMensais = 25;
    deslocamentosInclusos = 4;
    precoRecomendado = 3000;
    faixaComercial = "R$ 2.800 - R$ 3.500";
    slaAtendimento = "24h";
    break;
  case "premium":
    horasMensais = 50;
    deslocamentosInclusos = 8;
    precoRecomendado = 5500;
    faixaComercial = "R$ 5.000 - R$ 6.500";
    slaAtendimento = "12h";
    break;
  default:
    return { status: "Sob Avaliação Técnica", erro: "Plano não reconhecido." };
}

const urgenciaGastronomia = data.urgencia_gastronomia || false;
if (urgenciaGastronomia) {
    precoRecomendado *= 1.3;
}

return {
  status: "Processado",
  plano_selecionado: plano,
  horas_mensais: horasMensais,
  deslocamentos_inclusos: deslocamentosInclusos,
  materiais_inclusos: false,
  preco_recomendado: precoRecomendado,
  faixa_comercial: faixaComercial,
  imposto: "imposto_estimado_percentual",
  sla_atendimento: slaAtendimento,
  aviso: "Dependente de validação contábil."
};

